import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list yields premium of 5 G (processing fee only)");

  // Base premiums for main item types
  it.todo("single plain sword (no modifiers, first contract) yields 115 G premium");
  it.todo("single plain amulet yields 71 G premium (60 base + 6 first + 5 fee)");
  it.todo("single plain staff yields 93 G premium (80 base + 8 first + 5 fee)");
  it.todo("single plain potion yields 49 G premium (40 base + 4 first + 5 fee)");

  // Components and building blocks
  it.todo("2 runes yield 60 G premium (50 base + 5 first + 5 fee)");
  it.todo("3 runes (a block) yield 71 G premium (60 base + 6 first + 5 fee)");
  it.todo("4 runes yield 115 G premium (100 base + 10 first + 5 fee, no block)");
  it.todo("7 runes yield 198 G premium (175 base + 17.5 first rounded up + 5 fee)");
  it.todo("2 runes + 1 moonstone yield 88 G (75 base + 7.5 first + 5, no block: different types)");
  it.todo("3 runes + 3 moonstones yield 137 G (120 base + 12 first + 5, two separate blocks)");

  // Per-item modifiers: cursed
  it.todo("newcomer with a cursed sword yields 165 G premium (integration example)");

  // Per-item modifiers: high enchantment
  it.todo("sword with enchantment 5 (plain, first insurance) yields 148 G (100 + 30 + 13 + 5)");
  it.todo("sword with enchantment 4 (plain, first insurance) yields 115 G (no high-ench surcharge)");

  // Mixed item-level modifier scope
  it.todo("policy with cursed sword + plain amulet yields 236 G (210 base + 21 first + 5 fee)");

  // Policy-wide modifiers
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("follow-up contract gets 15% discount on second quote in scenario");
  it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G (integration)");

  // Rounding in MHPCO's favor
  it.todo("premium of 197.5 G rounds up to 198 G");

  // Claim: standard reimbursement
  it.todo("claim on plain sword (damage 500 G) pays out 400 G with cap remaining");
  it.todo("claim on rune (damage 200 G) pays out 100 G");

  // Claim: special clauses
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");

  // Claim: deductible per damage event
  it.todo("dragon attack damaging insured sword (500 G) and amulet (300 G) pays out 600 G");

  // Claim: cap behavior
  it.todo("policy with sword and amulet has cap 3200 G (insurance sum 1600 G)");
  it.todo("cursed sword has cap 2000 G (premium modifiers do not raise cap)");
  it.todo("policy with sword and 3 runes has insurance sum 1750 G");
  it.todo("two successive 1500 G claims on sword: first pays 1400 G, second pays 600 G");

  // Multiple items of same type
  it.todo("policy covers two swords with insurance sum 2000 G; both damaged → each has own deductible");

  // Error cases (CLI)
  it.todo("quote with unknown item type causes CLI to exit non-zero");
  it.todo("claim referencing item not in policy causes CLI to exit non-zero");
  it.todo("claim with negative damage amount causes CLI to exit non-zero");
  it.todo("claim with more damage entries of a type than policy covers causes CLI to exit non-zero");
});

