const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

const computeQuotePremium = (items: Item[]): number => {
  const itemBasePremiumSum = items.reduce(
    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0,
  );
  const firstInsuranceSurcharge = itemBasePremiumSum * FIRST_INSURANCE_RATE;
  return Math.ceil(itemBasePremiumSum + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: computeQuotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

