  | { op: "claim"; policy: number; incident: Incident };

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Incident = {
  cause?: string;
  damages: { itemType: string; amount: number }[];
};

export type Result = { premium: number } | { payout: number; remainingCap: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsBasePremium = (components: Item[]): number => {
  // Group by type, then for each group: count blocks of 3 + remainder.
  const counts = new Map<string, number>();
  for (const c of components) {
    counts.set(c.type, (counts.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    if (count === COMPONENT_BLOCK_SIZE) {
      total += COMPONENT_BLOCK_PREMIUM;
    } else {
      total += count * COMPONENT_BASE_PREMIUM;
    }
  }
  return total;
};

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((i) => !isComponent(i));
  const mainSum = mainItems.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  return mainSum + componentsBasePremium(components);
};

const computeQuotePremium = (items: Item[]): number => {
  const itemBasePremiumSum = itemsBasePremium(items);
  const firstInsuranceSurcharge = itemBasePremiumSum * FIRST_INSURANCE_RATE;
  return Math.ceil(itemBasePremiumSum + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: computeQuotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

